@spec mm_ppql_roundtrip_spec  src=tests/specs/mm_ppql_roundtrip_spec.lua  loc=125  sha=b5afaeb  cases=5
@exercises midiManager (h.mm)
@surface   mm:modify
@harness   fakeReaper:bindTake

# Intent
  Phase 1 (two-frame timing): ppqL/endppqL ride the per-event metadata
  channel through mm's save/load loop without explicit whitelist entries.
  Author notes/ccs through the real mm under modify(), then bring up a
  second mm against the same take and confirm ppqL/endppqL come back.

# Helpers
  @fn freshTake()  @ 10-16

# Cases
  @case 'note ppqL/endppqL survive a save/load round-trip'  [pure]  @ 20-36
  @case 'cc ppqL survives a save/load round-trip (lazy-sidecar allocates uuid)'  [pure]  @ 40-55
  @case 'pb ppqL survives a save/load round-trip'  [pure]  @ 59-74
  @case 'plain cc with no ppqL stays plain (no sidecar; no P_EXT entry)'  [pure]  @ 78-91
  @case 'mixed take: many events, all ppqL stamps survive concurrently'  [pure]  @ 95-123

# Uses (outbound edges)
  @use call mm:modify  @ 24,44,63,82,99

